-- Generated from /tmp/openlink-html-dav-category-summary.tsv
-- Purpose: apply content-derived schema:category WebDAV custom properties
-- Target: https://www.openlinksw.com/DAV/www2.openlinksw.com/data/html/
-- Run as a Virtuoso SQL user that can update DAV properties, e.g. DBA via isql.
-- Uses the built-in dba user password hash; no WebDAV password is embedded here.

USE DB;

DROP TABLE DB.DBA.OPENLINK_HTML_DAV_CATEGORY_STAGE;

CREATE TABLE DB.DBA.OPENLINK_HTML_DAV_CATEGORY_STAGE (
  PATH VARCHAR(2048) NOT NULL,
  CATEGORY LONG VARCHAR NOT NULL
);


CREATE PROCEDURE DB.DBA.APPLY_OPENLINK_HTML_SCHEMA_CATEGORY ()
{
  DECLARE _path VARCHAR;
  DECLARE _category LONG VARCHAR;
  DECLARE _dav_user VARCHAR;
  DECLARE _pwd VARCHAR;
  DECLARE _rc ANY;
  DECLARE _ok INTEGER;
  DECLARE _failed INTEGER;

  _ok := 0;
  _failed := 0;
  _dav_user := 'dba';
  _pwd := (SELECT pwd_magic_calc (U_NAME, U_PASSWORD, 1) FROM DB.DBA.SYS_USERS WHERE U_NAME = _dav_user);

  FOR SELECT PATH, CATEGORY FROM DB.DBA.OPENLINK_HTML_DAV_CATEGORY_STAGE DO
  {
    _path := PATH;
    _category := CATEGORY;
    _rc := DB.DBA.DAV_PROP_SET (_path, 'schema:category', _category, _dav_user, _pwd, 1);
    IF (DB.DBA.DAV_HIDE_ERROR (_rc) IS NULL)
      _failed := _failed + 1;
    ELSE
      _ok := _ok + 1;
  }

  RESULT_NAMES (event, ok_count, failed_count);
  RESULT ('schema:category apply complete', _ok, _failed);
}
;

DB.DBA.APPLY_OPENLINK_HTML_SCHEMA_CATEGORY ();

-- Spot-check the first few applied values.
SELECT TOP 10
  s.PATH,
  DB.DBA.DAV_PROP_GET (s.PATH, 'schema:category', 'dba', (SELECT pwd_magic_calc (U_NAME, U_PASSWORD, 1) FROM DB.DBA.SYS_USERS WHERE U_NAME = 'dba')) AS schema_category
FROM DB.DBA.OPENLINK_HTML_DAV_CATEGORY_STAGE s
ORDER BY s.PATH;

DROP PROCEDURE DB.DBA.APPLY_OPENLINK_HTML_SCHEMA_CATEGORY;

